def cham_tuong(x, y):
    for x1, y1, x2, y2 in DANH_SACH_TUONG:
        if y1 == y2:
            if min(x1, x2) - 10 <= x <= max(x1, x2) + 10:
                if abs(y - y1) < 12:
                    return True
        if x1 == x2:
            if min(y1, y2) - 10 <= y <= max(y1, y2) + 10:
                if abs(x - x1) < 12:
                    return True
    return False

